import React, { useState, useEffect, useRef } from 'react';

// ─── STYLES INJECTÉS EN JSX ───────────────────────────────────────────────────
const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&family=Space+Grotesk:wght@400;500;600;700;800&family=JetBrains+Mono:wght@300;400;500;600&display=swap');

  :root {
    --bg:#060912; --bg1:#0A0F1E; --bg2:#0D1526; --bg3:#111C30;
    --cyan:#06E6FF; --teal:#00F5D4; --green:#00FF88; --blue:#4D7CFF;
    --purple:#B06EFF; --pink:#FF4DC4; --gold:#FFD700; --red:#FF3D57;
    --t0:#FFFFFF; --t1:#E8EEFF; --t2:#8BA3CC; --t3:#3A5070;
    --brd:#142038; --brd2:#1A2C48;
  }

  .lp-root { font-family:'Inter',sans-serif; background:var(--bg); color:var(--t1); overflow-x:hidden; line-height:1.6; }
  .lp-root *,:before,:after { box-sizing:border-box; margin:0; padding:0; }

  /* SCROLLBAR */
  .lp-root ::-webkit-scrollbar{width:4px;}
  .lp-root ::-webkit-scrollbar-track{background:var(--bg);}
  .lp-root ::-webkit-scrollbar-thumb{background:var(--brd2);border-radius:2px;}

  /* NAV */
  .lp-nav {
    position:fixed;top:0;left:0;right:0;z-index:1000;
    padding:0 64px;height:72px;
    display:flex;align-items:center;justify-content:space-between;
    background:rgba(6,9,18,0.82);
    backdrop-filter:blur(20px) saturate(180%);
    border-bottom:1px solid rgba(255,255,255,0.04);
    transition:all 0.3s;
  }
  .lp-nav.scrolled { background:rgba(6,9,18,0.96); border-bottom-color:var(--brd); }
  .lp-nav-logo { display:flex;align-items:center;gap:9px;text-decoration:none;cursor:pointer;margin-left:20px; }
  .lp-nav-logo-icon {
    width:34px;height:34px;border-radius:9px;
    background:linear-gradient(135deg,#06E6FF,#00FF88);
    display:flex;align-items:center;justify-content:center;
    font-size:17px;box-shadow:0 0 20px rgba(6,230,255,0.4);
  }
  .lp-nav-logo-text { font-family:'Space Grotesk',sans-serif;font-weight:800;font-size:19px;color:var(--t0);letter-spacing:-0.5px; }
  .lp-nav-logo-text span { color:var(--cyan); }
  .lp-nav-links { display:flex;align-items:center;gap:6px; }
  .lp-nav-links a {
    padding:8px 16px;border-radius:8px;color:var(--t2);
    text-decoration:none;font-size:14px;font-weight:500;transition:all 0.18s;
  }
  .lp-nav-links a:hover { color:var(--t0);background:rgba(255,255,255,0.05); }
  .lp-nav-cta { display:flex;align-items:center;gap:10px; }
  .btn-ghost {
    padding:8px 18px;border-radius:9px;border:1px solid var(--brd2);
    background:transparent;color:var(--t1);font-size:13px;font-weight:600;
    cursor:pointer;font-family:'Inter',sans-serif;transition:all 0.18s;
  }
  .btn-ghost:hover { border-color:var(--cyan);color:var(--cyan); }
  .btn-primary-nav {
    padding:9px 20px;border-radius:9px;
    background:linear-gradient(135deg,#06E6FF,#00FF88);
    border:none;color:#060912;font-size:13px;font-weight:800;
    cursor:pointer;font-family:'Inter',sans-serif;
    transition:all 0.2s;box-shadow:0 0 20px rgba(6,230,255,0.3);
  }
  .btn-primary-nav:hover { transform:translateY(-1px);box-shadow:0 4px 30px rgba(6,230,255,0.45); }

  /* TICKER */
  .lp-ticker-wrap {
    overflow:hidden;background:rgba(6,230,255,0.04);
    border-top:1px solid rgba(6,230,255,0.1);
    border-bottom:1px solid rgba(6,230,255,0.1);
    padding:10px 0;white-space:nowrap;margin-top:68px;
  }
  .lp-ticker { display:inline-flex;gap:48px;animation:lp-ticker 30s linear infinite; }
  .lp-ticker-item { display:inline-flex;align-items:center;gap:8px;font-size:11px;font-weight:700;color:var(--t3);font-family:'JetBrains Mono',monospace; }
  .up { color:var(--green); }
  .dn { color:var(--red); }
  @keyframes lp-ticker { from{transform:translateX(0);}to{transform:translateX(-50%);} }

  /* HERO */
  .lp-hero {
    min-height:100vh;padding:150px 64px 100px;
    display:flex;flex-direction:column;align-items:center;
    text-align:center;position:relative;overflow:hidden;
  }
  .lp-hero-bg { position:absolute;inset:0;pointer-events:none; }
  .lp-orb { position:absolute;border-radius:50%;filter:blur(80px); }
  .lp-orb-1 {
    width:600px;height:600px;top:-100px;left:50%;transform:translateX(-50%);
    background:radial-gradient(circle,rgba(6,230,255,0.12),transparent 65%);
    animation:lp-pulse1 6s ease-in-out infinite;
  }
  .lp-orb-2 {
    width:400px;height:400px;bottom:0;left:-100px;
    background:radial-gradient(circle,rgba(0,255,136,0.08),transparent 65%);
    animation:lp-pulse2 6s ease-in-out 2s infinite;
  }
  .lp-orb-3 {
    width:350px;height:350px;bottom:0;right:-80px;
    background:radial-gradient(circle,rgba(176,110,255,0.07),transparent 65%);
    animation:lp-pulse2 6s ease-in-out 4s infinite;
  }
  .lp-grid-bg {
    position:absolute;inset:0;
    background-image:linear-gradient(rgba(77,124,255,0.06) 1px,transparent 1px),linear-gradient(90deg,rgba(77,124,255,0.06) 1px,transparent 1px);
    background-size:60px 60px;
    mask-image:radial-gradient(ellipse 80% 60% at 50% 0%,black,transparent);
    -webkit-mask-image:radial-gradient(ellipse 80% 60% at 50% 0%,black,transparent);
  }
  @keyframes lp-pulse1 {0%,100%{opacity:1;transform:scale(1) translateX(-50%);}50%{opacity:0.7;transform:scale(1.1) translateX(-50%);}}
  @keyframes lp-pulse2 {0%,100%{opacity:1;transform:scale(1);}50%{opacity:0.6;transform:scale(1.12);}}

  .lp-hero-badge {
    display:inline-flex;align-items:center;gap:8px;padding:6px 14px;border-radius:50px;
    border:1px solid rgba(6,230,255,0.3);background:rgba(6,230,255,0.07);
    font-size:11.5px;font-weight:700;color:var(--cyan);letter-spacing:0.5px;margin-bottom:28px;
    position:relative;z-index:1;
  }
  .lp-badge-dot { width:6px;height:6px;border-radius:50%;background:var(--cyan);box-shadow:0 0 8px var(--cyan);animation:lp-blink 1.5s ease infinite; }
  @keyframes lp-blink{0%,100%{opacity:1;}50%{opacity:0.2;}}

  .lp-hero h1 {
    font-family:'Space Grotesk',sans-serif;font-weight:800;
    font-size:clamp(48px,6vw,88px);line-height:1.06;
    color:var(--t0);letter-spacing:-1.5px;margin-bottom:22px;position:relative;z-index:1;
  }
  .lp-hero h1 .grad {
    background:linear-gradient(90deg,#06E6FF 0%,#00FF88 50%,#4D7CFF 100%);
    -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;
  }
  .lp-hero-sub { font-size:19px;color:var(--t2);max-width:720px;line-height:1.7;margin-bottom:36px;position:relative;z-index:1; }
  .lp-hero-actions { display:flex;gap:12px;align-items:center;justify-content:center;flex-wrap:wrap;margin-bottom:14px;position:relative;z-index:1; }

  .btn-hero-primary {
    padding:15px 32px;border-radius:12px;
    background:linear-gradient(135deg,#06E6FF,#00FF88);
    border:none;color:#060912;font-size:15px;font-weight:800;
    cursor:pointer;font-family:'Inter',sans-serif;
    transition:all 0.2s;box-shadow:0 0 40px rgba(6,230,255,0.35);
    display:flex;align-items:center;gap:8px;
  }
  .btn-hero-primary:hover { transform:translateY(-2px);box-shadow:0 8px 50px rgba(6,230,255,0.5); }
  .btn-hero-secondary {
    padding:15px 30px;border-radius:12px;
    border:1px solid var(--brd2);background:rgba(255,255,255,0.04);
    color:var(--t1);font-size:15px;font-weight:600;
    cursor:pointer;font-family:'Inter',sans-serif;
    transition:all 0.2s;display:flex;align-items:center;gap:8px;
  }
  .btn-hero-secondary:hover { border-color:var(--cyan);color:var(--cyan);background:rgba(6,230,255,0.05); }
  .lp-hero-note { font-size:11.5px;color:var(--t3);position:relative;z-index:1; }
  .lp-hero-note span { color:var(--t2); }

  /* STATS STRIP */
  .lp-hero-stats {
    display:flex;gap:0;margin-top:56px;
    border:1px solid var(--brd);border-radius:16px;
    background:rgba(13,21,38,0.8);backdrop-filter:blur(20px);
    overflow:hidden;position:relative;z-index:1;
  }
  .lp-hero-stat { padding:22px 40px;flex:1;text-align:center;border-right:1px solid var(--brd);position:relative; }
  .lp-hero-stat:last-child { border-right:none; }
  .lp-hero-stat:hover::after { opacity:1; }
  .lp-hero-stat::after {
    content:'';position:absolute;top:0;left:0;right:0;height:2px;
    background:linear-gradient(90deg,transparent,var(--cyan),transparent);opacity:0;transition:opacity 0.3s;
  }
  .lp-stat-val {
    font-family:'Space Grotesk',sans-serif;font-weight:800;font-size:28px;
    background:linear-gradient(135deg,#06E6FF,#00FF88);
    -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;
    line-height:1;margin-bottom:5px;
  }
  .lp-stat-label { font-size:12px;color:var(--t3);font-weight:600;letter-spacing:0.8px;text-transform:uppercase; }

  /* PRODUCT PREVIEW */
  .lp-preview { padding:100px 64px;position:relative; }
  .lp-preview-inner { max-width:1360px;margin:0 auto;position:relative; }
  .lp-preview-glow {
    position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);
    width:800px;height:400px;
    background:radial-gradient(ellipse,rgba(6,230,255,0.1),transparent 65%);
    filter:blur(40px);pointer-events:none;
  }
  .lp-preview-frame {
    border-radius:20px;border:1px solid var(--brd2);background:var(--bg2);overflow:hidden;
    box-shadow:0 40px 120px rgba(0,0,0,0.8),0 0 0 1px rgba(6,230,255,0.06),inset 0 1px 0 rgba(255,255,255,0.05);
  }
  .lp-topbar { background:var(--bg1);border-bottom:1px solid var(--brd);padding:12px 20px;display:flex;align-items:center;gap:10px; }
  .lp-dots { display:flex;gap:6px; }
  .lp-dot { width:10px;height:10px;border-radius:50%; }
  .lp-url {
    flex:1;margin:0 16px;background:var(--bg2);border-radius:6px;
    padding:5px 12px;font-size:11px;font-family:'JetBrains Mono',monospace;color:var(--t3);border:1px solid var(--brd);
  }
  .lp-dash { display:grid;grid-template-columns:180px 1fr;min-height:400px; }
  .lp-sidebar-prev { background:rgba(7,12,20,0.95);border-right:1px solid var(--brd);padding:16px 0; }
  .lp-sidebar-logo-prev { padding:0 16px 16px;border-bottom:1px solid var(--brd);margin-bottom:12px;display:flex;align-items:center;gap:8px; }
  .lp-nav-item { padding:8px 16px;font-size:11px;color:var(--t3);display:flex;align-items:center;gap:8px; }
  .lp-nav-item.active { color:var(--cyan);background:rgba(6,230,255,0.08);border-left:2px solid var(--cyan); }
  .lp-content { padding:16px; }
  .lp-kpi-row { display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:10px; }
  .lp-kpi { background:rgba(13,21,38,0.8);border:1px solid var(--brd);border-radius:10px;padding:12px;position:relative;overflow:hidden; }
  .lp-kpi-lbl { font-size:8px;color:var(--t3);font-weight:700;letter-spacing:1px;text-transform:uppercase;margin-bottom:4px; }
  .lp-kpi-val { font-family:'Space Grotesk',sans-serif;font-size:20px;font-weight:800; }
  .lp-kpi-badge {
    margin-top:4px;display:inline-block;padding:1px 6px;border-radius:3px;
    font-size:7px;font-weight:800;
  }
  .lp-charts { display:grid;grid-template-columns:2fr 1fr;gap:8px; }
  .lp-chart-card { background:rgba(13,21,38,0.8);border:1px solid var(--brd);border-radius:10px;padding:12px;overflow:hidden; }
  .lp-chart-lbl { font-size:8px;color:var(--t3);font-weight:700;letter-spacing:1px;text-transform:uppercase;margin-bottom:8px; }

  /* LOGOS */
  .lp-logos { padding:56px 64px;text-align:center;border-top:1px solid var(--brd);border-bottom:1px solid var(--brd);background:rgba(10,15,30,0.5); }
  .lp-logos p { font-size:11px;color:var(--t3);letter-spacing:2px;text-transform:uppercase;font-weight:700;margin-bottom:28px; }
  .lp-logos-row { display:flex;align-items:center;justify-content:center;gap:48px;flex-wrap:wrap;opacity:0.35;filter:grayscale(1); }
  .lp-logo-item { font-family:'Space Grotesk',sans-serif;font-size:16px;font-weight:800;color:var(--t0); }

  /* SECTIONS */
  .lp-section { padding:110px 64px; }
  .lp-section-inner { max-width:1360px;margin:0 auto; }
  .lp-section-tag {
    display:inline-flex;align-items:center;gap:6px;padding:4px 12px;border-radius:50px;
    border:1px solid rgba(6,230,255,0.25);background:rgba(6,230,255,0.06);
    font-size:10.5px;font-weight:700;color:var(--cyan);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:16px;
  }
  .lp-section h2 {
    font-family:'Space Grotesk',sans-serif;font-weight:800;font-size:clamp(36px,4vw,58px);
    line-height:1.1;color:var(--t0);letter-spacing:-1.5px;margin-bottom:14px;
  }
  .lp-section h2 em {
    font-style:normal;background:linear-gradient(90deg,var(--cyan),var(--green));
    -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;
  }
  .lp-section-sub { font-size:17px;color:var(--t2);max-width:640px;line-height:1.75; }

  /* FADE IN */
  .fade-in { opacity:0;transform:translateY(24px);transition:opacity 0.6s ease,transform 0.6s ease; }
  .fade-in.visible { opacity:1;transform:none; }

  /* FEATURES GRID */
  .lp-features-grid { display:grid;grid-template-columns:repeat(3,1fr);gap:20px;margin-top:70px; }
  .lp-feature-card {
    padding:32px;border-radius:16px;border:1px solid var(--brd);
    background:linear-gradient(145deg,rgba(13,21,38,0.9),rgba(10,15,28,0.95));
    position:relative;overflow:hidden;cursor:default;transition:all 0.25s;
  }
  .lp-feature-card:hover { border-color:var(--brd2);transform:translateY(-3px);box-shadow:0 20px 60px rgba(0,0,0,0.5); }
  .lp-feature-icon { width:44px;height:44px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:20px;margin-bottom:16px;background:rgba(255,255,255,0.04);border:1px solid var(--brd2); }
  .lp-feature-title { font-family:'Space Grotesk',sans-serif;font-weight:700;font-size:17px;color:var(--t0);margin-bottom:8px; }
  .lp-feature-desc { font-size:14.5px;color:var(--t2);line-height:1.7; }
  .lp-feature-tag { display:inline-block;margin-top:14px;padding:3px 9px;border-radius:5px;font-size:9px;font-weight:800;letter-spacing:0.5px;text-transform:uppercase; }

  /* BIG FEATURE */
  .lp-big-feat { display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center; }
  .lp-big-feat.reverse { direction:rtl; }
  .lp-big-feat.reverse > * { direction:ltr; }
  .lp-big-feat h3 { font-family:'Space Grotesk',sans-serif;font-weight:800;font-size:clamp(26px,2.5vw,38px);line-height:1.15;letter-spacing:-1px;color:var(--t0);margin-bottom:14px; }
  .lp-big-feat h3 em { font-style:normal;background:linear-gradient(90deg,var(--cyan),var(--teal));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text; }
  .lp-big-feat p { font-size:16px;color:var(--t2);line-height:1.8;margin-bottom:22px; }
  .lp-check-list { list-style:none;display:flex;flex-direction:column;gap:9px; }
  .lp-check-list li { display:flex;align-items:flex-start;gap:10px;font-size:15px;color:var(--t2); }
  .lp-check-ico { color:var(--green);font-weight:800;font-size:11px;width:18px;height:18px;border-radius:4px;background:rgba(0,255,136,0.1);border:1px solid rgba(0,255,136,0.25);display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:2px; }
  .lp-big-visual { border-radius:20px;overflow:hidden;border:1px solid var(--brd2);box-shadow:0 30px 80px rgba(0,0,0,0.7);background:var(--bg2); }
  .lp-visual-header { padding:10px 14px;background:var(--bg1);border-bottom:1px solid var(--brd);display:flex;align-items:center;gap:8px; }
  .lp-visual-title { font-size:10px;font-weight:700;color:var(--t2);letter-spacing:0.5px; }
  .lp-visual-badge { margin-left:auto;padding:2px 8px;border-radius:4px;font-size:8.5px;font-weight:800;background:rgba(6,230,255,0.12);border:1px solid rgba(6,230,255,0.25);color:var(--cyan); }
  .lp-visual-body { padding:16px; }

  /* COMPARE TABLE */
  .lp-compare-table { width:100%;border-collapse:separate;border-spacing:0;margin-top:48px; }
  .lp-compare-table th { padding:12px 16px;font-size:10.5px;font-weight:800;color:var(--t3);letter-spacing:1px;text-transform:uppercase;text-align:left;border-bottom:1px solid var(--brd); }
  .lp-compare-table th.hl { color:var(--cyan); }
  .lp-compare-table td { padding:12px 16px;font-size:13px;color:var(--t2);border-bottom:1px solid rgba(255,255,255,0.04); }
  .lp-compare-table td.hl { color:var(--t0);font-weight:600; }
  .lp-compare-table tr:hover td { background:rgba(255,255,255,0.02); }
  .cy { color:var(--green);font-weight:900; }
  .cn { color:var(--t3); }
  .cp { color:var(--gold); }

  /* PRICING */
  .lp-pricing-grid { display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-top:56px; }
  .lp-pricing-card {
    padding:30px 26px;border-radius:20px;border:1px solid var(--brd);
    background:linear-gradient(160deg,rgba(13,21,38,0.9),rgba(9,14,26,0.98));
    position:relative;overflow:hidden;transition:all 0.3s;
  }
  .lp-pricing-card:hover { transform:translateY(-4px); }
  .lp-pricing-card.popular {
    border-color:rgba(6,230,255,0.4);
    background:linear-gradient(160deg,rgba(6,230,255,0.05),rgba(0,255,136,0.03),rgba(9,14,26,0.98));
    box-shadow:0 0 0 1px rgba(6,230,255,0.1),0 30px 60px rgba(0,0,0,0.6);
  }
  .lp-popular-badge { position:absolute;top:16px;right:16px;padding:3px 10px;border-radius:50px;background:linear-gradient(135deg,var(--cyan),var(--green));font-size:9px;font-weight:800;color:#060912;letter-spacing:0.5px; }
  .lp-plan { font-size:11px;font-weight:800;color:var(--t3);letter-spacing:2px;text-transform:uppercase;margin-bottom:16px; }
  .lp-price { font-family:'Space Grotesk',sans-serif;font-weight:800;font-size:48px;color:var(--t0);line-height:1;margin-bottom:4px;letter-spacing:-2px; }
  .lp-price sup { font-size:18px;vertical-align:super;letter-spacing:0; }
  .lp-period { font-size:12px;color:var(--t3);margin-bottom:6px; }
  .lp-save { display:inline-block;padding:2px 8px;border-radius:4px;font-size:9px;font-weight:800;background:rgba(0,255,136,0.12);border:1px solid rgba(0,255,136,0.25);color:var(--green);margin-bottom:22px; }
  .lp-divider { height:1px;background:var(--brd);margin:20px 0; }
  .lp-price-feats { list-style:none;display:flex;flex-direction:column;gap:10px;margin-bottom:26px; }
  .lp-price-feats li { display:flex;align-items:flex-start;gap:10px;font-size:13px;color:var(--t2); }
  .lp-price-feats li.dim { color:var(--t3); }
  .btn-plan { width:100%;padding:13px;border-radius:10px;font-size:14px;font-weight:700;cursor:pointer;font-family:'Inter',sans-serif;transition:all 0.2s;border:none; }
  .btn-plan.outline { background:transparent;border:1px solid var(--brd2);color:var(--t1); }
  .btn-plan.outline:hover { border-color:var(--cyan);color:var(--cyan); }
  .btn-plan.filled { background:linear-gradient(135deg,var(--cyan),var(--green));color:#060912;box-shadow:0 0 24px rgba(6,230,255,0.3); }
  .btn-plan.filled:hover { box-shadow:0 4px 36px rgba(6,230,255,0.5);transform:translateY(-1px); }

  /* TESTIMONIALS */
  .lp-testi-grid { display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-top:52px; }
  .lp-testi-card { padding:24px;border-radius:16px;border:1px solid var(--brd);background:linear-gradient(145deg,rgba(13,21,38,0.8),rgba(10,15,28,0.9));transition:all 0.25s; }
  .lp-testi-card:hover { border-color:var(--brd2);transform:translateY(-2px); }
  .lp-stars { font-size:11px;color:var(--gold);margin-bottom:12px;letter-spacing:1px; }
  .lp-testi-text { font-size:14.5px;color:var(--t2);line-height:1.75;margin-bottom:18px;font-style:italic; }
  .lp-testi-text strong { color:var(--cyan);font-style:normal; }
  .lp-testi-author { display:flex;align-items:center;gap:10px; }
  .lp-avatar { width:36px;height:36px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:800;color:#060912;flex-shrink:0; }
  .lp-testi-name { font-size:13px;font-weight:700;color:var(--t0); }
  .lp-testi-role { font-size:11px;color:var(--t3); }
  .lp-testi-pnl { display:inline-flex;align-items:center;gap:4px;font-size:10px;font-weight:700;color:var(--green);background:rgba(0,255,136,0.08);border:1px solid rgba(0,255,136,0.2);padding:2px 8px;border-radius:4px;margin-top:4px; }

  /* FAQ */
  .lp-faq-list { margin-top:48px;display:flex;flex-direction:column;gap:10px;max-width:900px; }
  .lp-faq-item { border:1px solid var(--brd);border-radius:12px;background:rgba(13,21,38,0.7);overflow:hidden; }
  .lp-faq-q { padding:20px 24px;display:flex;justify-content:space-between;align-items:center;cursor:pointer;font-size:15.5px;font-weight:600;color:var(--t1);transition:color 0.2s;user-select:none; }
  .lp-faq-q:hover { color:var(--cyan); }
  .lp-faq-arrow { color:var(--t3);font-size:20px;transition:transform 0.25s;line-height:1; }
  .lp-faq-item.open .lp-faq-arrow { transform:rotate(45deg);color:var(--cyan); }
  .lp-faq-a { max-height:0;overflow:hidden;transition:max-height 0.3s ease; }
  .lp-faq-item.open .lp-faq-a { max-height:200px; }
  .lp-faq-a-inner { padding:0 24px 20px;font-size:14.5px;color:var(--t2);line-height:1.75; }

  /* CTA */
  .lp-cta {
    padding:100px 64px;text-align:center;position:relative;overflow:hidden;
    background:linear-gradient(180deg,rgba(6,9,18,0) 0%,rgba(6,230,255,0.04) 50%,rgba(6,9,18,0) 100%);
    border-top:1px solid var(--brd);border-bottom:1px solid var(--brd);
  }
  .lp-cta-orb { position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:700px;height:300px;background:radial-gradient(ellipse,rgba(6,230,255,0.08),transparent 65%);filter:blur(60px);pointer-events:none; }
  .lp-cta h2 { font-family:'Space Grotesk',sans-serif;font-weight:800;font-size:clamp(38px,4.5vw,64px);letter-spacing:-1.5px;color:var(--t0);margin-bottom:14px;position:relative; }
  .lp-cta h2 em { font-style:normal;background:linear-gradient(90deg,var(--cyan),var(--green));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text; }
  .lp-cta p { font-size:18px;color:var(--t2);margin-bottom:36px;position:relative; }
  .lp-cta-actions { display:flex;gap:12px;justify-content:center;flex-wrap:wrap;position:relative; }
  .lp-cta-note { font-size:11.5px;color:var(--t3);margin-top:16px;position:relative; }

  /* FOOTER */
  .lp-footer { padding:70px 64px 40px;border-top:1px solid var(--brd); }
  .lp-footer-inner { max-width:1360px;margin:0 auto; }
  .lp-footer-top { display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:40px;margin-bottom:50px; }
  .lp-footer-brand p { font-size:13px;color:var(--t3);line-height:1.7;margin-top:12px;max-width:320px; }
  .lp-footer-col h4 { font-size:11px;font-weight:800;color:var(--t2);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:14px; }
  .lp-footer-col a { display:block;font-size:13px;color:var(--t3);text-decoration:none;margin-bottom:10px;transition:color 0.18s; }
  .lp-footer-col a:hover { color:var(--t1); }
  .lp-footer-bottom { padding-top:24px;border-top:1px solid var(--brd);display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px; }
  .lp-footer-bottom p { font-size:12px;color:var(--t3); }
  .lp-footer-bottom p span { color:var(--t2); }
  .lp-social-row { display:flex;gap:8px; }
  .lp-social-btn { width:32px;height:32px;border-radius:8px;border:1px solid var(--brd);background:transparent;color:var(--t3);font-size:14px;display:flex;align-items:center;justify-content:center;cursor:pointer;transition:all 0.18s;text-decoration:none; }
  .lp-social-btn:hover { border-color:var(--cyan);color:var(--cyan); }

  /* METRICS */
  .lp-metrics-grid { display:grid;grid-template-columns:repeat(2,1fr);gap:8px;margin-bottom:12px; }
  .lp-metric-box { padding:12px;border-radius:10px;background:rgba(255,255,255,0.03);border:1px solid var(--brd); }
  .lp-metric-box .lbl { font-size:8px;color:var(--t3);font-weight:700;letter-spacing:1px;text-transform:uppercase;margin-bottom:4px; }
  .lp-metric-box .val { font-family:'JetBrains Mono',monospace;font-size:17px;font-weight:500; }
`;

// ─── LIVE TICKER — DONNÉES TEMPS RÉEL ────────────────────────────────────────
//
//  Architecture :
//  • BTC/USD     → Binance WebSocket  (tick par tick, < 1s)
//  • Forex       → Binance WebSocket  (EURUSDT, GBPUSDT, etc. — perpetual)
//  • Indices US  → Stooq CSV (S&P500=^SPX, NASDAQ=^NDX, DJI=^DJI, RUT=^RUT)
//                  via allorigins proxy, refresh 15s (données différées ~15min)
//  • Tous les prix affichent le % de variation 24h en direct
//
// ─────────────────────────────────────────────────────────────────────────────

// Symboles Binance (WebSocket miniTicker 24h)

// Paires forex réelles via frankfurter (refresh 10s)

// Indices US via Stooq

const DECIMALS_MAP = {
  'BTC/USD':0, 'ETH/USD':2, 'SOL/USD':2,
  'EUR/USD':4,'GBP/USD':4,'USD/JPY':2,'USD/CHF':4,'AUD/USD':4,'USD/CAD':4,'GBP/JPY':2,
  'S&P 500':2,'NASDAQ':2,'DOW JONES':2,'RUSSELL 2K':2,
};

// Fallback au cas où les APIs sont indisponibles
const FALLBACK_PRICES = {
  'BTC/USD'   : { price:83200,   pct:+1.24  },
  'ETH/USD'   : { price:2010,    pct:+0.87  },
  'SOL/USD'   : { price:132,     pct:+1.45  },
  'EUR/USD'   : { price:1.0842,  pct:+0.12  },
  'GBP/USD'   : { price:1.2710,  pct:+0.21  },
  'USD/JPY'   : { price:149.82,  pct:-0.08  },
  'USD/CHF'   : { price:0.9012,  pct:+0.04  },
  'AUD/USD'   : { price:0.6532,  pct:-0.11  },
  'USD/CAD'   : { price:1.3590,  pct:+0.07  },
  'GBP/JPY'   : { price:190.42,  pct:+0.13  },
  'S&P 500'   : { price:5680,    pct:+0.34  },
  'NASDAQ'    : { price:19800,   pct:+0.56  },
  'DOW JONES' : { price:41500,   pct:+0.22  },
  'RUSSELL 2K': { price:2100,    pct:-0.14  },
};

// ── ORDER d'affichage dans le ticker ──────────────────────────────────────────
const TICKER_ORDER = [
  'S&P 500','NASDAQ','DOW JONES','RUSSELL 2K',
  'BTC/USD','ETH/USD','SOL/USD',
  'EUR/USD','GBP/USD','USD/JPY','USD/CHF','AUD/USD','USD/CAD','GBP/JPY',
];

// ─────────────────────────────────────────────────────────────────────────────
// Hook principal — gère toutes les sources de données
// ─────────────────────────────────────────────────────────────────────────────
function useLiveTicker() {
  const [data, setData] = React.useState(() => {
    const d = {};
    TICKER_ORDER.forEach(name => {
      d[name] = { price: FALLBACK_PRICES[name].price, pct: FALLBACK_PRICES[name].pct, flash: null };
    });
    return d;
  });

  const update = React.useCallback((name, price, pct) => {
    setData(prev => {
      const prevPrice = prev[name]?.price ?? price;
      const flash = price > prevPrice ? 'up' : price < prevPrice ? 'dn' : null;
      const next = { ...prev, [name]: { price, pct: pct ?? prev[name]?.pct ?? 0, flash } };
      if (flash) setTimeout(() => setData(d => ({ ...d, [name]: { ...d[name], flash: null } })), 700);
      return next;
    });
  }, []);

  // ── 1. CRYPTO via Binance WebSocket (tick par tick, <1s) ─────────────────
  // BTC, ETH, BNB, SOL, XRP en simultané via stream combiné
  React.useEffect(() => {
    let ws, retryT;
    const STREAMS = [
      'btcusdt@miniTicker',
      'ethusdt@miniTicker',
      'solusdt@miniTicker',
    ].join('/');
    const CRYPTO_MAP = {
      'btcusdt': 'BTC/USD',
      'ethusdt': 'ETH/USD',
      'solusdt': 'SOL/USD',
    };
    const connect = () => {
      try {
        ws = new WebSocket(`wss://stream.binance.com:9443/stream?streams=${STREAMS}`);
        ws.onmessage = (e) => {
          try {
            const msg = JSON.parse(e.data);
            const d = msg.data;
            const name = CRYPTO_MAP[d?.s?.toLowerCase()];
            if (!name) return;
            update(name, parseFloat(d.c), parseFloat(d.P));
          } catch {}
        };
        ws.onerror = () => {};
        ws.onclose = () => { retryT = setTimeout(connect, 3000); };
      } catch {}
    };
    connect();
    return () => { try { ws.close(); } catch {} clearTimeout(retryT); };
  }, [update]);

  // ── 2. Forex via API proxy Vercel (refresh 30s) ──────────────────────────
  // Passe par /api/market-data pour éviter les problèmes CORS
  React.useEffect(() => {
    let prevRates = {};
    const fetchForex = async () => {
      try {
        const res = await fetch('/api/market-data?type=forex');
        const json = await res.json();
        if (!json.pairs) return;
        Object.entries(json.pairs).forEach(([name, price]) => {
          if (!price) return;
          const prev = prevRates[name] || price;
          const pct = prev ? +((price - prev) / prev * 100).toFixed(3) : 0;
          prevRates[name] = price;
          update(name, price, pct);
        });
      } catch {}
    };
    fetchForex();
    const t = setInterval(fetchForex, 30000);
    return () => clearInterval(t);
  }, [update]);

  // ── 3. Indices US via API proxy Vercel (refresh 20s) ─────────────────────
  // Yahoo Finance côté serveur pour éviter le blocage CORS navigateur
  React.useEffect(() => {
    let prevPrices = {};
    const fetchIndices = async () => {
      try {
        const res = await fetch('/api/market-data?type=indices');
        const json = await res.json();
        if (!json.indices) return;
        Object.entries(json.indices).forEach(([name, { price, pct }]) => {
          if (!price) return;
          const prev = prevPrices[name];
          const finalPct = prev ? +((price - prev) / prev * 100).toFixed(2) : pct;
          prevPrices[name] = price;
          update(name, price, finalPct);
        });
      } catch {}
    };
    fetchIndices();
    const t = setInterval(fetchIndices, 20000);
    return () => clearInterval(t);
  }, [update]);

  return data;
}

// ─── LIVE TICKER BAR COMPONENT ────────────────────────────────────────────────
function LiveTickerBar() {
  const data = useLiveTicker();
  const doubled = [...TICKER_ORDER, ...TICKER_ORDER];

  const fmt = (name, price) => {
    if (!price && price !== 0) return '···';
    const d = DECIMALS_MAP[name] ?? 4;
    if (price >= 10000) return price.toLocaleString('en-US', {maximumFractionDigits:0});
    if (price >= 1000)  return price.toLocaleString('en-US', {maximumFractionDigits:2});
    return price.toFixed(d);
  };


  return (
    <div style={{
      overflow:'hidden',
      background:'rgba(3,5,12,0.98)',
      borderTop:'1px solid rgba(6,230,255,0.06)',
      borderBottom:'1px solid rgba(255,255,255,0.04)',
      padding:'11px 0',
      whiteSpace:'nowrap',
      marginTop:72,
      position:'relative',
    }}>
      {/* Fade edges */}
      <div style={{position:'absolute',left:0,top:0,bottom:0,width:80,background:'linear-gradient(90deg,rgba(3,5,12,0.98),transparent)',zIndex:2,pointerEvents:'none'}} />
      <div style={{position:'absolute',right:0,top:0,bottom:0,width:80,background:'linear-gradient(270deg,rgba(3,5,12,0.98),transparent)',zIndex:2,pointerEvents:'none'}} />

      <div style={{display:'inline-flex',gap:0,animation:'lp-ticker 50s linear infinite'}}>
        {doubled.map((name, i) => {
          const d = data[name] || FALLBACK_PRICES[name];
          const price = d?.price ?? 0;
          const pct   = d?.pct   ?? 0;
          const flash = d?.flash;
          const isPos = pct >= 0;

          // Couleur du prix : flash vert/rouge, sinon blanc sobre
          const priceColor = flash === 'up' ? '#00FF88'
                           : flash === 'dn' ? '#FF4455'
                           : '#D8E8FF';

          return (
            <span key={`${name}-${i}`} style={{
              display:'inline-flex',
              alignItems:'center',
              gap:8,
              padding:'0 20px',
              borderRight:'1px solid rgba(255,255,255,0.035)',
            }}>
              {/* Nom */}
              <span style={{
                color:'#4A6080',
                fontFamily:"'JetBrains Mono',monospace",
                fontSize:9.5,
                fontWeight:600,
                letterSpacing:'1px',
                textTransform:'uppercase',
              }}>{name}</span>

              {/* Prix */}
              <span style={{
                color: priceColor,
                fontFamily:"'JetBrains Mono',monospace",
                fontSize:12,
                fontWeight:500,
                transition:'color 0.5s ease',
                letterSpacing:'0.3px',
              }}>
                {fmt(name, price)}
              </span>

              {/* % variation 24h */}
              <span style={{
                display:'inline-flex',
                alignItems:'center',
                gap:3,
                padding:'2px 6px',
                borderRadius:4,
                background: isPos ? 'rgba(0,192,112,0.1)' : 'rgba(255,68,85,0.1)',
                border: `1px solid ${isPos ? 'rgba(0,192,112,0.2)' : 'rgba(255,68,85,0.2)'}`,
                fontFamily:"'JetBrains Mono',monospace",
                fontSize:9.5,
                fontWeight:700,
                color: isPos ? '#00C070' : '#FF4455',
                letterSpacing:'0.3px',
              }}>
                {isPos ? '▲' : '▼'} {Math.abs(pct).toFixed(2)}%
              </span>
            </span>
          );
        })}
      </div>
    </div>
  );
}

